// Time:  O(n + s)
// Space: O(n + s)

// bfs, flood fill, quick select
class Solution {
public:
    long long maxAlternatingSum(vector<int>& nums, vector<vector<int>>& swaps) {
        vector<vector<int>> adj(size(nums));
        for (const auto& s : swaps) {
            adj[s[0]].emplace_back(s[1]);
            adj[s[1]].emplace_back(s[0]);
        }
        vector<bool> lookup(size(adj));
        const auto& bfs = [&](int u) {
            vector<int> q;
            if (lookup[u]) {
                return q;
            }
            lookup[u] = true;
            q.emplace_back(u);
            for (int i = 0; i < size(q); ++i) {
                for (const auto& v : adj[q[i]]) {
                    if (lookup[v]) {
                        continue;
                    }
                    lookup[v] = true;
                    q.emplace_back(v);
                }
            }
            return q;
        };

        int64_t result = accumulate(cbegin(nums), cend(nums), 0ll);
        for (int u = 0; u < size(nums); ++u) {
            const auto& g = bfs(u);
            if (empty(g)) {
                continue;
            }
            const int l = accumulate(cbegin(g), cend(g), 0, [](const auto& total, const auto& x) {
                return total + x % 2;
            });
            vector<int> arr;
            arr.reserve(size(g));
            for (const auto& i : g) {
                arr.emplace_back(nums[i]);
            }
            nth_element(begin(arr), begin(arr) + l, end(arr));
            result -= 2 * accumulate(cbegin(arr), cbegin(arr) + l, 0ll);
        }
        return result;
    }
};

# Time:  O(n + s)
# Space: O(n + s)

import random


# bfs, flood fill, quick select
class Solution(object):
    def maxAlternatingSum(self, nums, swaps):
        """
        :type nums: List[int]
        :type swaps: List[List[int]]
        :rtype: int
        """
        def nth_element(nums, n, compare=lambda a, b: a < b):
            def tri_partition(nums, left, right, target, compare):
                mid = left
                while mid <= right:
                    if nums[mid] == target:
                        mid += 1
                    elif compare(nums[mid], target):
                        nums[left], nums[mid] = nums[mid], nums[left]
                        left += 1
                        mid += 1
                    else:
                        nums[mid], nums[right] = nums[right], nums[mid]
                        right -= 1
                return left, right

            left, right = 0, len(nums)-1
            while left <= right:
                pivot_idx = random.randint(left, right)
                pivot_left, pivot_right = tri_partition(nums, left, right, nums[pivot_idx], compare)
                if pivot_left <= n <= pivot_right:
                    return
                elif pivot_left > n:
                    right = pivot_left-1
                else:  # pivot_right < n.
                    left = pivot_right+1

        def bfs(u):
            q = []
            if lookup[u]:
                return q
            lookup[u] = True
            q.append(u)
            for u in q:
                for v in adj[u]:
                    if lookup[v]:
                        continue
                    lookup[v] = True
                    q.append(v)
            return q

        adj = [[] for _ in xrange(len(nums))]
        for i, j in swaps:
            adj[i].append(j)
            adj[j].append(i)
        lookup = [False]*len(adj)
        result = sum(nums)
        for u in xrange(len(nums)):
            g = bfs(u)
            if not g:
                continue
            l = sum(i%2 for i in g)
            arr = [nums[i] for i in g]
            nth_element(arr, l)
            result -= 2*sum(arr[i] for i in xrange(l))
        return result
